/**
 * Client for the SperaxOS agent API.
 *
 * When no API key is configured, operates in mock mode — generating synthetic
 * agent events without connecting to the real API.
 */
export class SperaxOSClient {
    baseUrl;
    apiKey;
    mockMode;
    constructor(baseUrl, apiKey) {
        this.baseUrl = baseUrl;
        this.apiKey = apiKey;
        this.mockMode = !apiKey;
        if (this.mockMode) {
            console.log('[SperaxOSClient] No API key — operating in mock mode');
        }
    }
    async spawnAgent(config) {
        if (this.mockMode) {
            return {
                agentId: `mock_agent_${Date.now()}`,
                name: config.name ?? `Mock${config.role}`,
                role: config.role,
                createdAt: Date.now(),
            };
        }
        const res = await fetch(`${this.baseUrl}/agents/v1/spawn`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                Authorization: `Bearer ${this.apiKey}`,
            },
            body: JSON.stringify(config),
        });
        if (!res.ok)
            throw new Error(`SperaxOS spawn failed: ${res.status}`);
        return res.json();
    }
    async executeTask(agentId, task) {
        if (this.mockMode)
            return;
        const res = await fetch(`${this.baseUrl}/agents/v1/agents/${agentId}/tasks`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                Authorization: `Bearer ${this.apiKey}`,
            },
            body: JSON.stringify(task),
        });
        if (!res.ok)
            throw new Error(`SperaxOS executeTask failed: ${res.status}`);
    }
    async getAgentStatus(agentId) {
        if (this.mockMode) {
            return {
                agentId,
                name: agentId,
                role: 'unknown',
                createdAt: Date.now(),
            };
        }
        const res = await fetch(`${this.baseUrl}/agents/v1/agents/${agentId}`, {
            headers: { Authorization: `Bearer ${this.apiKey}` },
        });
        if (!res.ok)
            throw new Error(`SperaxOS getAgentStatus failed: ${res.status}`);
        return res.json();
    }
    subscribeEvents(agentId, callback) {
        if (this.mockMode) {
            // No real WebSocket in mock mode — events are generated by AgentManager
            return () => { };
        }
        const ws = new WebSocket(`${this.baseUrl.replace(/^http/, 'ws')}/agents/v1/stream?agentId=${agentId}&apiKey=${this.apiKey}`);
        ws.onmessage = (msg) => {
            try {
                const event = JSON.parse(msg.data);
                callback(event);
            }
            catch {
                // ignore
            }
        };
        return () => ws.close();
    }
    async healthCheck() {
        if (this.mockMode)
            return true;
        try {
            const res = await fetch(`${this.baseUrl}/health`, {
                headers: { Authorization: `Bearer ${this.apiKey}` },
                signal: AbortSignal.timeout(5000),
            });
            return res.ok;
        }
        catch {
            return false;
        }
    }
}
